package kotlinx.coroutines

import kotlin.coroutines.*
import kotlin.test.*

/**
 * Tests for CoroutineContext.isActive behaviour fix.
 * This test verifies that CoroutineContext.isActive returns true when there is no Job in the context,
 * making it consistent with CoroutineScope.isActive.
 */
class CoroutineContextIsActiveTest : TestBase() {

    @Test
    fun testCoroutineContextActiveWithoutJob() {
        // Test that isActive returns true when there's no Job
        val emptyContext = EmptyCoroutineContext
        assertTrue(emptyContext.isActive, "isActive should be true when there is no Job")
    }

    @Test
    fun testCoroutineContextActiveWithJob() = runTest {
        // Test that isActive works correctly when there is a Job
        val job = launch {
            expect(1)
            assertTrue(coroutineContext.isActive)
            delay(Long.MAX_VALUE)
            expectUnreached()
        }
        expect(2)
        assertTrue(coroutineContext.isActive, "Coroutine should be active")
        job.cancel()
        job.join()
        assertFalse(coroutineContext.isActive, "Coroutine should be inactive after cancellation")
        finish(3)
    }

    @Test
    fun testCoroutineContextActiveWithCancelledJob() = runTest {
        val job = Job()
        val context = job + EmptyCoroutineContext
        job.cancel()
        job.join()
        assertFalse(context.isActive, "isActive should be false for cancelled job")
    }

    @Test
    fun testCoroutineContextActiveWithCompletedJob() = runTest {
        val job = Job()
        job.complete()
        job.join()
        val context = job + EmptyCoroutineContext
        assertFalse(context.isActive, "isActive should be false for completed job")
    }

    @Test
    fun testCoroutineContextActiveConsistentWithScope() = runTest {
        // Verify that CoroutineContext.isActive is consistent with CoroutineScope.isActive
        val job = Job()

        // Both should return true for active job
        val context = job + EmptyCoroutineContext
        assertEquals(context.isActive, true, "Context isActive should be true")

        val scope = CoroutineScope(context)
        assertEquals(scope.isActive, true, "Scope isActive should be true")
        assertEquals(context.isActive, scope.isActive, "Context and scope isActive should match")

        // Cancel the job
        job.cancel()
        job.join()

        // Both should return false after cancellation
        assertEquals(context.isActive, false, "Context isActive should be false")
        assertEquals(scope.isActive, false, "Scope isActive should be false")
        assertEquals(context.isActive, scope.isActive, "Context and scope isActive should still match")
    }

    @Test
    fun testCoroutineContextActiveInDelayLoop() = runTest {
        var iterations = 0
        val job = launch {
            var i = 0
            while (coroutineContext.isActive && i < 10) { // Should not break due to isActive
                expect(i + 1)
                i++
                yield()
                iterations++
            }
        }
        // Let the coroutine run
        repeat(20) { yield() }

        // Verify loop ran to completion (not broken by isActive)
        assertEquals(iterations, 10, "Loop should have completed all iterations")
        finish(11)
    }

    @Test
    fun testCoroutineContextActiveWithNonCancellableContext() = runTest {
        val context = NonCancellable
        // NonCancellable has a job that cannot be cancelled
        assertTrue(context.isActive, "NonCancellable context should be active")

        val scope = CoroutineScope(context)
        assertEquals(scope.isActive, context.isActive, "Scope and context should match")
    }

    @Test
    fun testGlobalScopeConsistency() {
        // GlobalScope doesn't have a Job, but with the fix, both should return true
        assertEquals(GlobalScope.isActive, true, "GlobalScope should be active")
        assertEquals(GlobalScope.coroutineContext.isActive, true, "GlobalScope context should be active")
        assertEquals(GlobalScope.isActive, GlobalScope.coroutineContext.isActive, "GlobalScope and context should match")
    }

    @Test
    fun testCoroutineContextActiveInSuspendFunMainStyle() = runTest {
        // Simulate a suspend fun main style entry point
        suspend fun simulateEntryPointWithoutJob(): Int {
            var total = 0
            // Even without a Job, isActive should return true and not break the loop
            var i = 0
            while (coroutineContext.isActive && i < 5) {
                total += i
                i++
                yield()
            }
            return total // Should return 10 (0+1+2+3+4)
        }

        val result = simulateEntryPointWithoutJob()
        assertEquals(10, result, "Should have completed all iterations")
    }

    @Test
    fun testCoroutineContextActiveWithJobCompletion() = runTest {
        val job = launch {
            var sum = 0
            var i = 0
            // Loop should continue while coroutine is active
            while (coroutineContext.isActive && i < 100) {
                sum += i
                if (i == 50) {
                    expect(1)
                }
                i++
                yield()
            }
            expect(3)
            sum
        }

        // Let it start
        yield()
        yield()

        expect(2)
        job.cancel()
        job.join()
        finish(4)
    }

    @Test
    fun testCoroutineContextActiveWithMultipleContextElements() {
        val dispatcher = Dispatchers.Default
        val context = dispatcher + EmptyCoroutineContext

        // Should return true even with only a dispatcher (no Job)
        assertTrue(context.isActive, "Context with dispatcher only should be active")
    }

    @Test
    fun testCoroutineContextActivePreservesJobBehaviour() = runTest {
        // Create a job in various states and verify isActive matches Job.isActive
        var completedIterations = 0

        val job = Job()
        val context1 = job + EmptyCoroutineContext
        assertEquals(context1.isActive, job.isActive, "Should match new job state")

        job.complete()
        job.join()
        val context2 = job + EmptyCoroutineContext
        assertEquals(context2.isActive, job.isActive, "Should match completed job state")

        val job2 = Job()
        val job2Context = job2 + EmptyCoroutineContext
        job2.cancel()
        job2.join()
        assertEquals(job2Context.isActive, job2.isActive, "Should match cancelled job state")
    }
}"}

