{"file_path":"/project/kotlinx-coroutines-core/common/test/CoroutineContextIsActiveIssueTest.kt","content":"/*
 * Copyright 2016-2021 JetBrains s.r.o. Use of this source code is governed by the Apache 2.0 license.
 */

package kotlinx.coroutines

import kotlin.coroutines.*
import kotlin.test.*

/**
 * Test demonstrating fix for CoroutineContext.isActive issue.
 * 
 * Before the fix: CoroutineContext.isActive returned false when there was no Job in the context,
 * which caused issues with entry points like Ktor and suspend fun main that might not have a Job.
 * 
 * After the fix: CoroutineContext.isActive returns true when there is no Job in the context,
 * making it consistent with CoroutineScope.isActive and avoiding incorrect loop termination.
 */
class CoroutineContextIsActiveIssueTest : TestBase() {

    @Test
    fun testSuspenFunMainScenario() {
        // Simulates suspend fun main entry point that may not have a Job
        // Before the fix: loop would exit immediately because isActive == false
        // After the fix: loop continues processing because isActive == true when no Job

        suspend fun simulateEntryointWithoutJob(): Int {
            var sum = 0
            var iterations = 0

            // This loop should NOT terminate based on isActive when there's no Job
            while (coroutineContext.isActive && iterations < 10) {
                sum += iterations
                iterations++
                yield()
            }

            return sum
        }

        // In a real scenario, you'd run this in runTest or similar
        // For demonstration, we'll just verify the context behavior
        val context = EmptyCoroutineContext
        assertTrue(context.isActive, "Context without Job should be active")
    }

    @Test
    fun testConsistencyBetweenContextAndScope() {
        // Verify that CoroutineContext.isActive and CoroutineScope.isActive behave consistently

        // Test 1: Without a Job
        val emptyContext = EmptyCoroutineContext
        val emptyScope = CoroutineScope(emptyContext)

        assertEquals(emptyContext.isActive, true, "Context without Job should be active")
        assertEquals(emptyScope.isActive, true, "Scope without Job should be active")
        assertEquals(emptyContext.isActive, emptyScope.isActive, "Should be consistent")

        // Test 2: With an active Job
        val activeJob = Job()
        val activeContext = activeJob + EmptyCoroutineContext
        val activeScope = CoroutineScope(activeContext)

        assertEquals(activeContext.isActive, true, "Context with active Job should be active")
        assertEquals(activeScope.isActive, true, "Scope with active Job should be active")
        assertEquals(activeContext.isActive, activeScope.isActive, "Should be consistent")

        // Test 3: With a cancelled Job
        activeJob.cancel()
        activeJob.join()

        assertEquals(activeContext.isActive, false, "Context with cancelled Job should be inactive")
        assertEquals(activeScope.isActive, false, "Scope with cancelled Job should be inactive")
        assertEquals(activeContext.isActive, activeScope.isActive, "Should still be consistent")
    }

    @Test
    fun testGlobalScopeBehaviour() {
        // GlobalScope is a known entry point without a Job
        // Before the fix: GlobalScope.coroutineContext.isActive returned false (incorrect)
        // After the fix: It returns true (correct, consistent with GlobalScope.isActive)

        assertEquals(GlobalScope.isActive, true, "GlobalScope.isActive should be true")
        assertEquals(GlobalScope.coroutineContext.isActive, true, "GlobalScope.coroutineContext.isActive should be true")
        assertEquals(GlobalScope.isActive, GlobalScope.coroutineContext.isActive, "Should match")
    }

    @Test
    fun testDispatcherOnlyContext() {
        // Contexts with only a dispatcher (common in frameworks) should be active
        val dispatcherContext = Dispatchers.Default
        assertTrue(dispatcherContext.isActive, "Context with only dispatcher should be active")
    }

    @Test
    fun testLoopWithCancellationCheck() = runTest {
        // This test shows that the fix allows loops to check for cancellation
        // without incorrectly terminating when there's no Job

        var iterations = 0
        val maxIterations = 10

        val job = launch {
            // Loop continues while coroutine is active
            while (coroutineContext.isActive && iterations < maxIterations) {
                expect(iterations + 1)
                iterations++
                yield()
            }
        }

        // Let it complete
        job.join()

        // Verify all iterations completed
        assertEquals(maxIterations, iterations, "All iterations should complete")
        finish(maxIterations + 1)
    }

    @Test
    fun testJobPresenceVsAbsence() {
        // Test demonstrates the key behavioral change

        // Case 1: Job is present and active
        val activeJob = Job()
        val contextWithJob = activeJob + EmptyCoroutineContext
        assertEquals(true, contextWithJob.isActive, "Should be true when Job is active")

        // Case 2: Job is present but cancelled
        activeJob.cancel()
        activeJob.join()
        assertEquals(false, contextWithJob.isActive, "Should be false when Job is cancelled")

        // Case 3: No Job present (the fix)
        val contextWithoutJob = EmptyCoroutineContext
        assertEquals(true, contextWithoutJob.isActive, "Should be true when no Job is present")
    }
}"}

{"file_path":"/project/kotlinx-coroutines-core/common/test/RealWorldIsActiveScenarioTest.kt","content":"/*
