package kotlinx.coroutines

import kotlin.coroutines.*
import kotlin.test.*

/**
 * Test that demonstrates the real-world use case described in the issue.
 * 
 * Issue: Users reported that CoroutineContext.isActive was error-prone when used with
 * entry points like Ktor and suspend fun main because it returned false when there was no Job.
 * 
 * This test verifies that the fix makes CoroutineContext.isActive usable in these scenarios
 * by returning true when there is no Job (meaning the coroutine cannot be cancelled).
 */
class RealWorldIsActiveScenarioTest : TestBase() {

    /**
     * Simulates a Ktor-like entry point where the context might not have a Job.
     * Before the fix, loops would terminate immediately because isActive returned false.
     * After the fix, loops continue processing because isActive returns true.
     */
    @Test
    fun testKtorStyleEntryPoint() = runTest {
        suspend fun ktorHandler(): Int {
            var processed = 0

            // This is the pattern users want to use: check isActive in a processing loop
            while (coroutineContext.isActive && processed < 5) {
                processed++
                yield()
            }

            return processed
        }

        val result = ktorHandler()
        // With the fix, should process all items
        assertEquals(5, result, "Should have processed all items")
    }

    /**
     * Test a pattern where users check isActive to avoid long-running computations
     * after cancellation. This should work correctly both with and without a Job.
     */
    @Test
    fun testLongRunningComputationPattern() = runTest {
        var iterations = 0
        val maxIterations = 100

        suspend fun computation() {
            // Common pattern: break loop if cancelled
            while (coroutineContext.isActive && iterations < maxIterations) {
                // Do some work
                iterations++
                yield()

                // If we have a Job and it's cancelled, isActive becomes false
                // If we don't have a Job, isActive stays true (correct behavior)
            }
        }

        // Test with a Job
        val job = launch {
            computation()
        }

        // Let it start
        yield()

        // Cancel the job
        job.cancel()
        job.join()

        // Should have stopped due to cancellation
        assertTrue(iterations < maxIterations, "Should have stopped early due to cancellation")

        // Test without a Job (cannot cancel)
        launch {
            iterations = 0
            computation()
        }

        yield()
        yield()
    }

    /**
     * Test the specific scenario from the issue: GlobalScope.isActive vs context.isActive
     */
    @Test
    fun testGlobalScopeConsistency() {
        // Issue noted that GlobalScope.isActive behaved differently from context.isActive
        // Both should return true since GlobalScope doesn't have a Job

        val globalScopeActive = GlobalScope.isActive
        val contextActive = GlobalScope.coroutineContext.isActive

        assertEquals(true, globalScopeActive, "GlobalScope.isActive should be true")
        assertEquals(true, contextActive, "GlobalScope.context.isActive should be true")
        assertEquals(globalScopeActive, contextActive, "Should be consistent")
    }

    /**
     * Test that demonstrates the problem before the fix:
     * Code that checks for cancellation might incorrectly stop processing
     * when there's simply no Job to check.
     */
    @Test
    fun testCancellationHandlingWithoutJob() = runTest {
        suspend fun processItems(items: List<Int>): Int {
            var sum = 0

            // This pattern is now safe: it will continue processing
            // when there's no Job (can't be cancelled anyway)
            for (item in items) {
                sum += item
                // Check if cancelled
                if (!coroutineContext.isActive) {
                    break
                }
                yield()
            }

            return sum
        }

        val items = (1..10).toList()
        val result = processItems(items)

        // Should process all items
        assertEquals(55, result, "Should have processed all items")
    }

    /**
     * Test that cancellation still works correctly when there IS a Job
     */
    @Test
    fun testCancellationWithJob() = runTest {
        var count = 0

        suspend fun countLoop() {
            while (coroutineContext.isActive && count < 1000) {
                count++
                yield()
            }
        }

        val job = launch {
            countLoop()
        }

        // Let it start
        yield()

        // Cancel it
        job.cancel()
        job.join()

        // Should have stopped before 1000
        assertTrue(count < 1000, "Should have stopped before reaching 1000")
        assertTrue(count > 0, "Should have made some progress")
    }

    /**
     * Test mixing CoroutineContext.isActive and CoroutineScope.isActive
     */
    @Test
    fun testMixedUsage() = runTest {
        suspend fun mixedCheck(): Boolean {
            val fromContext = coroutineContext.isActive
            val fromScope = isActive

            // Should always be the same
            assertEquals(fromContext, fromScope, "Should match")

            return fromContext
        }

        assertTrue(mixedCheck(), "Should be true")
    }

    /**
     * Test with a context that has only a dispatcher (common in frameworks)
     */
    @Test
    fun testDispatcherOnlyContext() {
        val context = Dispatchers.Default

        // Context with just a dispatcher should be "active"
        // because there's no Job to cancel it
        assertTrue(context.isActive, "Dispatcher-only context should be active")
    }

    /**
     * Test that using context.isActive for flow processing works correctly
     */
    @Test
    fun testFlowProcessingPattern() = runTest {
        suspend fun processFlow(items: List<Int>): Int {
            var sum = 0

            for (item in items) {
                // Break if cancelled
                if (!coroutineContext.isActive) {
                    break
                }
                sum += item
                yield()
            }

            return sum
        }

        val result = processFlow(listOf(1, 2, 3, 4, 5))
        assertEquals(15, result, "Should process all items")
    }

    /**
     * Test the exact scenario from the issue description:
     * non-kotlinx.coroutines entry points should work correctly
     */
    @Test
    fun testScenarioFromIssue() {
        // "such behaviour can be error-prone when used with non-kotlinx.coroutines
        // entry points, such as Ktor and suspend fun main"

        // Simulating an entry point without a Job
        val entryContext = EmptyCoroutineContext

        // Before fix: would return false, breaking loops
        // After fix: returns true, allowing loops to continue
        assertTrue(entryContext.isActive, "Should be true for entry point without Job")

        // Should work the same as wrapping in a scope
        val scope = CoroutineScope(entryContext)
        assertEquals(entryContext.isActive, scope.isActive, "Should match scope behavior")
    }
}"}

