package kotlinx.coroutines.flow

import kotlinx.coroutines.*
import kotlin.test.*

/**
 * Test to verify that SharedFlow.toList(destination) correctly passes the destination parameter.
 * Issue: https://github.com/Kotlin/kotlinx.coroutines/issues/XXXX
 * Previously, SharedFlow.toList destination parameter was not passed to Flow.toList, causing incorrect behavior.
 */
class SharedFlowToListFixTest : TestBase() {

    @Test
    fun testSharedFlowToListWithDestination() = runTest {
        val sharedFlow = MutableSharedFlow<Int>(replay = 3)

        // Emit some values
        repeat(5) { sharedFlow.emit(it) }

        // Create a mutable list and collect into it
        val acc = mutableListOf<Int>()
        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            sharedFlow.toList(acc)
        }

        // Wait a bit to ensure collection starts
        yield()

        // Cancel to stop collection (since SharedFlow never completes)
        job.cancel()
        job.join()

        // Verify that acc contains values (it should not be empty)
        // Note: The specific behavior depends on timing with replay buffer
        assertTrue(acc.isNotEmpty(), "Expected accumulator to contain values")
    }

    @Test
    fun testSharedFlowToListCorrectlyFillsDestination() = runTest {
        val sharedFlow = MutableSharedFlow<Int>(replay = 2)

        // Emit values
        sharedFlow.emit(1)
        sharedFlow.emit(2)
        sharedFlow.emit(3)

        // Create a mutable list with initial values
        val acc = mutableListOf(100, 200)
        val initialAccSize = acc.size

        // Cancel immediately after starting (SharedFlow is slow)
        val job = launch {
            sharedFlow.toList(acc)
        }
        yield()
        job.cancel()
        job.join()

        // After the fix, acc should have more items than initial
        // because toList should use the provided destination
        assertTrue(acc.size >= initialAccSize, 
            "Expected accumulator size to be at least $initialAccSize, but was ${acc.size}")
    }

    @Test
    fun testSharedFlowToSetWithDestination() = runTest {
        val sharedFlow = MutableSharedFlow<Int>(replay = 2)

        // Emit values
        sharedFlow.emit(1)
        sharedFlow.emit(2)
        sharedFlow.emit(1) // duplicate

        // Create a mutable set and collect into it
        val acc = mutableSetOf<Int>()
        val job = launch {
            sharedFlow.toSet(acc)
        }
        yield()
        job.cancel()
        job.join()

        // After fix, should have collected some values into the set
        assertTrue(acc.isNotEmpty(), "Expected set to contain values")
    }
}"}

{"file_path":"/project/test_yield_fix.kt","content":"import kotlinx.coroutines.*

// Test 1: Basic yield with delay
fun test1() = runBlocking {
    val outputs = mutableListOf<String>()
    launch(start = CoroutineStart.UNDISPATCHED) {
        delay(1)
        outputs.add("first")
    }
    Thread.sleep(100)
    yield()
    outputs.add("second")
    println("Test 1 - Basic yield with delay")
    println(outputs)
    println("Expected: [first, second]")
    println("Test passed: ${outputs == listOf("first", "second")}")
    println()
}

// Test 2: Multiple delayed tasks
fun test2() = runBlocking {
    val outputs = mutableListOf<String>()
    launch(start = CoroutineStart.UNDISPATCHED) {
        delay(1)
        outputs.add("1")
    }
    launch(start = CoroutineStart.UNDISPATCHED) {
        delay(1)
        outputs.add("2")
    }
    Thread.sleep(100)
    yield()
    outputs.add("3")
    println("Test 2 - Multiple delayed tasks")
    println(outputs)
    println("Test passed: ${outputs.size == 3}")
    println()
}

// Test 3: Yield when no delayed tasks
fun test3() = runBlocking {
    val outputs = mutableListOf<String>()
    launch {
        outputs.add("first")
    }
    yield()
    outputs.add("second")
    println("Test 3 - Yield without delay")
    println(outputs)
    println("Expected: [first, second]")
    println("Test passed: ${outputs == listOf("first", "second")}")
    println()
}

fun main() {
    test1()
    test2()
    test3()
}"}

