fun main() {
    println("Testing yield with delayed tasks...")

    // Test 1: Basic yield with delayed task (from issue description)
    runBlocking {
        val outputs = mutableListOf<String>()

        launch(start = CoroutineStart.UNDISPATCHED) {
            delay(1)
            outputs.add("first")
        }

        Thread.sleep(100) // Ensure the 1ms delay has expired

        yield()
        outputs.add("second")

        println("Test 1 - Outputs: $outputs")
        println("Expected: [first, second]")
        println("Test 1 " + if (outputs == listOf("first", "second")) "PASSED" else "FAILED")
    }

    // Test 2: Simple scenario from the issue
    runBlocking {
        val outputs = mutableListOf<String>()

        val job = launch {
            delay(1)
            println("This should be first")
            outputs.add("first")
        }

        Thread.sleep(100) // Wait for delay to expire

        // Yield should allow the delayed job to execute
        while (!job.isCompleted) {
            yield()
        }

        println("This should be second")
        outputs.add("second")

        println("\nTest 2 - Outputs: $outputs")
        println("Expected: [first, second]")
        println("Test 2 " + if (outputs == listOf("first", "second")) "PASSED" else "FAILED")
    }

    println("\nAll tests completed!")
}"}

