package kotlinx.coroutines.internal

import kotlinx.coroutines.*
import java.lang.reflect.*
import java.util.*
import java.util.concurrent.locks.*
import kotlin.concurrent.*

private val throwableFields = Throwable::class.java.fieldsCountOrDefault(-1)
private typealias Ctor = (Throwable) -> Throwable?

private val ctorCache = try {
    if (ANDROID_DETECTED) WeakMapCtorCache
    else ClassValueCtorCache
} catch (e: Throwable) {
    // Fallback on Java 6 or exotic setups
    WeakMapCtorCache
}

@Suppress("UNCHECKED_CAST")
internal fun <E : Throwable> tryCopyException(exception: E): E? {
    // Fast path for CopyableThrowable
    if (exception is CopyableThrowable<*>) {
        return runCatching { exception.createCopy() as E? }.getOrNull()
    }
    return ctorCache.get(exception.javaClass).invoke(exception) as E?
}

private fun <E : Throwable> createConstructor(clz: Class<E>): Ctor {
    val nullResult: Ctor = { null } // Pre-cache class
    // Skip reflective copy if an exception has additional fields (that are usually populated in user-defined constructors)
    if (throwableFields != clz.fieldsCountOrDefault(0)) return nullResult
    /*
    * Try to reflectively find constructor(), constructor(message, cause), constructor(cause) or constructor(message).
    * Exceptions are shared among coroutines, so we should copy exception before recovering current stacktrace.
    */
    // Prioritize constructors with more significant parameter types (cause > message) and more parameters
    val constructors = clz.constructors.sortedByDescending { constructor ->
        val types = constructor.parameterTypes
        // Score based on parameter types, then size
        val priorityScore = types.sumOf { param ->
            when (param) {
                Throwable::class.java -> 2 // cause is most valuable
                String::class.java -> 1 // message is second
                else -> 0
            }
        }
        Pair(priorityScore, types.size)
    }
    for (constructor in constructors) {
        val result = createSafeConstructor(constructor)
        if (result != null) return result
    }
    return nullResult
}

private fun createSafeConstructor(constructor: Constructor<*>): Ctor? {
    val p = constructor.parameterTypes
    return when (p.size) {
        2 -> when {
            p[0] == String::class.java && p[1] == Throwable::class.java ->
                safeCtor { e -> constructor.newInstance(e.message, e) as Throwable }
            else -> null
        }
        1 -> when (p[0]) {
            Throwable::class.java ->
                safeCtor { e -> constructor.newInstance(e) as Throwable }
            String::class.java ->
                safeCtor { e -> (constructor.newInstance(e.message) as Throwable).also { it.initCause(e) } }
            else -> null
        }
        0 -> safeCtor { e -> (constructor.newInstance() as Throwable).also { it.initCause(e) } }
        else -> null
    }
}

private inline fun safeCtor(crossinline block: (Throwable) -> Throwable): Ctor =
    { e -> runCatching { block(e) }.getOrNull() }

private fun Class<*>.fieldsCountOrDefault(defaultValue: Int) =
    kotlin.runCatching { fieldsCount() }.getOrDefault(defaultValue)

private tailrec fun Class<*>.fieldsCount(accumulator: Int = 0): Int {
    val fieldsCount = declaredFields.count { !Modifier.isStatic(it.modifiers) }
    val totalFields = accumulator + fieldsCount
    val superClass = superclass ?: return totalFields
    return superClass.fieldsCount(totalFields)
}

internal abstract class CtorCache {
    abstract fun get(key: Class<out Throwable>): Ctor
}

private object WeakMapCtorCache : CtorCache() {
    private val cacheLock = ReentrantReadWriteLock()
    private val exceptionCtors: WeakHashMap<Class<out Throwable>, Ctor> = WeakHashMap()

    override fun get(key: Class<out Throwable>): Ctor {
        cacheLock.read { exceptionCtors[key]?.let { return it } }
        cacheLock.write {
            exceptionCtors[key]?.let { return it }
            return createConstructor(key).also { exceptionCtors[key] = it }
        }
    }
}

@IgnoreJreRequirement
private object ClassValueCtorCache : CtorCache() {
    private val cache = object : ClassValue<Ctor>() {
        override fun computeValue(type: Class<*>?): Ctor {
            @Suppress("UNCHECKED_CAST")
            return createConstructor(type as Class<out Throwable>)
        }
    }

    override fun get(key: Class<out Throwable>): Ctor = cache.get(key)
}"}

{"file_path":"/project/test_fix_nested_exceptions.kt","content":"import kotlinx.coroutines.*
import org.junit.Test
import org.junit.Assert.*

class NestedException : RuntimeException {
    constructor(message: String) : super(message)
    constructor(cause: Throwable) : super(cause)
    constructor() : super()
}

class TestFixNestedExceptions {

    @Test
    fun testNestedExceptionWithCauseConstructor() = runTest {
        val result = runCatching {
            coroutineScope<Unit> {
                throw NestedException(IllegalStateException("ERROR"))
            }
        }
        val ex = result.exceptionOrNull() ?: error("Expected to fail")
        assertTrue("Exception should be NestedException", ex is NestedException)
        assertTrue("Cause should be IllegalStateException", ex.cause is IllegalStateException)
        assertEquals("Error message should be 'ERROR'", "ERROR", (ex.cause as IllegalStateException).message)
        // Verify the exception is not doubly nested
        val originalCause = ex.cause
        assertNotNull("Cause should not be null", originalCause)
        // The cause should not have the same type as the exception (which would indicate nesting)
        assertFalse("Exception should not be nested", originalCause?.javaClass == ex.javaClass)
    }

    @Test
    fun testNestedExceptionWithMessageConstructor() = runTest {
        // Test with message-only constructor to ensure proper behavior
        val result = runCatching {
            coroutineScope<Unit> {
                throw NestedException("test message")
            }
        }
        val ex = result.exceptionOrNull() ?: error("Expected to fail")
        assertTrue("Exception should be NestedException", ex is NestedException)
        assertEquals("Message should be preserved", "test message", ex.message)
        assertNull("Cause should be null when no cause provided", ex.cause)
    }

    @Test
    fun testExceptionWithCauseAndMessage() = runTest {
        // Test using standard exception with both message and cause
        val innerException = IllegalStateException("Inner error")
        val outerException = RuntimeException("Outer error", innerException)

        val result = runCatching {
            coroutineScope<Unit> {
                throw outerException
            }
        }
        val ex = result.exceptionOrNull() ?: error("Expected to fail")
        assertTrue("Exception should be RuntimeException", ex is RuntimeException)
        assertEquals("Outer message should be preserved", "Outer error", ex.message)
        assertNotNull("Should have a cause", ex.cause)
        assertTrue("Cause should be IllegalStateException", ex.cause is IllegalStateException)
        assertEquals("Inner message should be preserved", "Inner error", ex.cause?.message)
    }

    @Test
    fun testExceptionWithOnlyCause() = runTest {
        // Test with exception that only has cause, no message
        val innerException = NullPointerException("NPE message")
        val result = runCatching {
            coroutineScope<Unit> {
                throw RuntimeException(innerException)
            }
        }
        val ex = result.exceptionOrNull() ?: error("Expected to fail")
        assertTrue("Exception should be RuntimeException", ex is RuntimeException)
        assertTrue("Cause should be NullPointerException", ex.cause is NullPointerException)
        assertEquals("NPE message should be preserved", "NPE message", ex.cause?.message)
        // Verify no double nesting
        assertFalse("Exception should not be nested", ex.cause?.javaClass == ex.javaClass)
    }
}"}

