{"file_path":"/project/test_nested_exception_fix.kt","content":"import kotlinx.coroutines.*
import kotlin.test.*

class NestedException : RuntimeException {
    constructor(message: String) : super(message)
    constructor(cause: Throwable) : super(cause)
    constructor() : super()
}

fun main() {
    testNestedExceptionWithCauseConstructor()
    testNestedExceptionWithMessageConstructor()
    testExceptionWithCauseAndMessage()
    testExceptionWithOnlyCause()
    println("All tests passed!")
}

fun testNestedExceptionWithCauseConstructor() {
    val result = runCatching {
        runBlocking {
            coroutineScope<Unit> {
                throw NestedException(IllegalStateException("ERROR"))
            }
        }
    }
    val ex = result.exceptionOrNull() ?: error("Expected to fail")
    assertTrue("Exception should be NestedException", ex is NestedException)
    assertTrue("Cause should be IllegalStateException", ex.cause is IllegalStateException)
    assertEquals("Error message should be 'ERROR'", "ERROR", (ex.cause as IllegalStateException).message)
    // Verify the exception is not doubly nested
    val originalCause = ex.cause
    assertNotNull("Cause should not be null", originalCause)
    // The cause should not have the same type as the exception (which would indicate nesting)
    assertFalse("Exception should not be nested", originalCause?.javaClass == ex.javaClass)
    println("testNestedExceptionWithCauseConstructor passed")
}

fun testNestedExceptionWithMessageConstructor() {
    // Test with message-only constructor to ensure proper behavior
    val result = runCatching {
        runBlocking {
            coroutineScope<Unit> {
                throw NestedException("test message")
            }
        }
    }
    val ex = result.exceptionOrNull() ?: error("Expected to fail")
    assertTrue("Exception should be NestedException", ex is NestedException)
    assertEquals("Message should be preserved", "test message", ex.message)
    assertNull("Cause should be null when no cause provided", ex.cause)
    println("testNestedExceptionWithMessageConstructor passed")
}

fun testExceptionWithCauseAndMessage() {
    // Test using standard exception with both message and cause
    val innerException = IllegalStateException("Inner error")
    val outerException = RuntimeException("Outer error", innerException)

    val result = runCatching {
        runBlocking {
            coroutineScope<Unit> {
                throw outerException
            }
        }
    }
    val ex = result.exceptionOrNull() ?: error("Expected to fail")
    assertTrue("Exception should be RuntimeException", ex is RuntimeException)
    assertEquals("Outer message should be preserved", "Outer error", ex.message)
    assertNotNull("Should have a cause", ex.cause)
    assertTrue("Cause should be IllegalStateException", ex.cause is IllegalStateException)
    assertEquals("Inner message should be preserved", "Inner error", ex.cause?.message)
    println("testExceptionWithCauseAndMessage passed")
}

fun testExceptionWithOnlyCause() {
    // Test with exception that only has cause, no message
    val innerException = NullPointerException("NPE message")
    val result = runCatching {
        runBlocking {
            coroutineScope<Unit> {
                throw RuntimeException(innerException)
            }
        }
    }
    val ex = result.exceptionOrNull() ?: error("Expected to fail")
    assertTrue("Exception should be RuntimeException", ex is RuntimeException)
    assertTrue("Cause should be NullPointerException", ex.cause is NullPointerException)
    assertEquals("NPE message should be preserved", "NPE message", ex.cause?.message)
    // Verify no double nesting
    assertFalse("Exception should not be nested", ex.cause?.javaClass == ex.javaClass)
    println("testExceptionWithOnlyCause passed")
}"}

