 12→
 13→private val throwableFields = Throwable::class.java.fieldsCountOrDefault(-1)
 14→private typealias Ctor = (Throwable) -> Throwable?
 15→
 16→private val ctorCache = try {
 17→    if (ANDROID_DETECTED) WeakMapCtorCache
 18→    else ClassValueCtorCache
 19→} catch (e: Throwable) {
 20→    // Fallback on Java 6 or exotic setups
 21→    WeakMapCtorCache
 22→}
 23→
 24→@Suppress("UNCHECKED_CAST")
 25→internal fun <E : Throwable> tryCopyException(exception: E): E? {
 26→    // Fast path for CopyableThrowable
 27→    if (exception is CopyableThrowable<*>) {
 28→        return runCatching { exception.createCopy() as E? }.getOrNull()
 29→    }
 30→    return ctorCache.get(exception.javaClass).invoke(exception) as E?
 31→}
 32→
 33→private fun <E : Throwable> createConstructor(clz: Class<E>): Ctor {
 34→    val nullResult: Ctor = { null } // Pre-cache class
 35→    // Skip reflective copy if an exception has additional fields (that are usually populated in user-defined constructors)
 36→    if (throwableFields != clz.fieldsCountOrDefault(0)) return nullResult
 37→    /*
 38→    * Try to reflectively find constructor(), constructor(message, cause), constructor(cause) or constructor(message).
 39→    * Exceptions are shared among coroutines, so we should copy exception before recovering current stacktrace.
 40→    */
 41→    // Prioritize constructors with more significant parameter types (cause > message) and more parameters
 42→    val constructors = clz.constructors.sortedByDescending { constructor ->
 43→        val types = constructor.parameterTypes
 44→        // Score based on parameter types, then size
 45→        val priorityScore = types.sumOf { param ->
 46→            when (param) {
 47→                Throwable::class.java -> 2 // cause is most valuable
 48→                String::class.java -> 1 // message is second
 49→                else -> 0
 50→            }
 51→        }
 52→        Pair(priorityScore, types.size)
 53→    }
 54→    for (constructor in constructors) {
 55→        val result = createSafeConstructor(constructor)
 56→        if (result != null) return result
 57→    }
 58→    return nullResult
 59→}
 60→
 61→private fun createSafeConstructor(constructor: Constructor<*>): Ctor? {
 62→    val p = constructor.parameterTypes
 63→    return when (p.size) {
 64→        2 -> when {
 65→            p[0] == String::class.java && p[1] == Throwable::class.java ->
 66→                safeCtor { e -> constructor.newInstance(e.message, e) as Throwable }
 67→            else -> null
 68→        }
 69→        1 -> when (p[0]) {
 70→            Throwable::class.java ->
 71→                safeCtor { e -> constructor.newInstance(e) as Throwable }
 72→            String::class.java ->
 73→                safeCtor { e -> (constructor.newInstance(e.message) as Throwable).also { it.initCause(e) } }
 74→            else -> null
 75→        }
 76→        0 -> safeCtor { e -> (constructor.newInstance() as Throwable).also { it.initCause(e) } }
 77→        else -> null
 78→    }
 79→}
 80→
 81→private inline fun safeCtor(crossinline block: (Throwable) -> Throwable): Ctor =
 82→    { e -> runCatching { block(e) }.getOrNull() }
 83→
 84→private fun Class<*>.fieldsCountOrDefault(defaultValue: Int) =
 85→    kotlin.runCatching { fieldsCount() }.getOrDefault(defaultValue)
 86→
 87→private tailrec fun Class<*>.fieldsCount(accumulator: Int = 0): Int {
 88→    val fieldsCount = declaredFields.count { !Modifier.isStatic(it.modifiers) }
 89→    val totalFields = accumulator + fieldsCount
 90→    val superClass = superclass ?: return totalFields
 91→    return superClass.fieldsCount(totalFields)
 92→}
 93→
 94→internal abstract class CtorCache {
 95→    abstract fun get(key: Class<out Throwable>): Ctor
 96→}
 97→
 98→private object WeakMapCtorCache : CtorCache() {
 99→    private val cacheLock = ReentrantReadWriteLock()
100→    private val exceptionCtors: WeakHashMap<Class<out Throwable>, Ctor> = WeakHashMap()
101→
102→    override fun get(key: Class<out Throwable>): Ctor {
103→        cacheLock.read { exceptionCtors[key]?.let { return it } }
104→        cacheLock.write {
105→            exceptionCtors[key]?.let { return it }
106→            return createConstructor(key).also { exceptionCtors[key] = it }
107→        }
108→    }
109→}
110→
111→@IgnoreJreRequirement
112→private object ClassValueCtorCache : CtorCache() {
113→    private val cache = object : ClassValue<Ctor>() {
114→        override fun computeValue(type: Class<*>?): Ctor {
115→            @Suppress("UNCHECKED_CAST")
116→            return createConstructor(type as Class<out Throwable>)
117→        }
118→    }
119→
120→    override fun get(key: Class<out Throwable>): Ctor = cache.get(key)
121→}

