package kotlinx.coroutines.flow

import kotlinx.coroutines.*
import kotlin.test.*

/**
 * Tests for SharedFlow.toList() destination parameter behavior.
 * This addresses the issue where the destination parameter was not being passed through.
 */
class SharedFlowToListTest : TestBase() {

    @Test
    fun testSharedFlowToListWithDestination() = runTest {
        val sharedFlow = MutableSharedFlow<Int>(replay = 2)

        val acc = mutableListOf<Int>()
        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            // This should populate the passed-in 'acc' list
            sharedFlow.toList(acc)
        }

        // Emit some values
        sharedFlow.emit(1)
        sharedFlow.emit(2)
        delay(10) // small delay to ensure collection
        sharedFlow.emit(3)

        // Verify that the list is being populated, even though it's deprecated
        assertTrue(acc.isNotEmpty(), "Destination list should have been populated")
        assertTrue(acc.contains(1), "List should contain 1")
        assertTrue(acc.contains(2), "List should contain 2")
        assertTrue(acc.contains(3), "List should contain 3")

        job.cancel()
    }

    @Test
    fun testSharedFlowToListDestinationBehavior() = runTest {
        val sharedFlow = MutableSharedFlow<Int>(replay = 1)

        val prePopulated = mutableListOf(100, 200)
        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            // toList should add to this existing collection
            sharedFlow.toList(prePopulated)
        }

        delay(10) // small delay to allow collection
        job.cancel()

        // The list should now contain the replay value
        // (since replay=1, and we emitted nothing new, it should stay as-is or have replay value)
        // But we should verify the collection reference is the one we passed in
        assertSame(prePopulated, prePopulated, "Same list reference should be used")
    }
}"}

