import kotlinx.coroutines.*
import kotlin.test.Test
import kotlin.time.Duration.Companion.seconds

class CallbackFlowTimeoutTest {

    @Test
    fun testCallbackFlowCloseExceptionPropagatesWithTimeout() = runBlocking {
        val flow = callbackFlow<Int> {
            close(IllegalStateException("Test Exception"))
        }.timeout(5.seconds)

        var caughtException: Exception? = null
        try {
            flow.collect()
        } catch (e: Exception) {
            caughtException = e
        }

        check(caughtException is IllegalStateException) {
            "Expected IllegalStateException but got ${caughtException?.javaClass?.simpleName}"
        }
        check("Test Exception" in (caughtException?.message ?: "")) {
            "Expected message 'Test Exception' but got '${caughtException?.message}'"
        }
    }

    @Test
    fun testCallbackFlowNormalCloseWorks() = runBlocking {
        val flow = callbackFlow<Int> {
            close()
        }.timeout(5.seconds)

        var collectedCount = 0
        flow.collect {
            collectedCount++
        }

        check(collectedCount == 0) {
            "Expected 0 collected items but got $collectedCount"
        }
