        }
        check("Test Exception" in (caughtException?.message ?: "")) {
            "Expected message 'Test Exception' but got '${caughtException?.message}'"
        }
    }

    @Test
    fun testCallbackFlowNormalCloseWorks() = runBlocking {
        val flow = callbackFlow<Int> {
            close()
        }.timeout(5.seconds)

        var collectedCount = 0
        flow.collect {
            collectedCount++
        }

        check(collectedCount == 0) {
            "Expected 0 collected items but got $collectedCount"
        }
    }

