package kotlinx.coroutines.flow

import kotlinx.coroutines.*
import kotlinx.coroutines.channels.*
import kotlinx.coroutines.flow.internal.*
import kotlinx.coroutines.selects.*
import kotlin.jvm.*
import kotlin.time.*

/* Scaffolding for Knit code examples
<!--- TEST_NAME FlowDelayTest -->
<!--- PREFIX .*-duration-.*
----- INCLUDE .*-duration-.*
----- INCLUDE .*
import kotlinx.coroutines.*
import kotlinx.coroutines.flow.*
import kotlin.time.Duration.Companion.milliseconds

fun main() = runBlocking {
----- SUFFIX .*
.toList().joinToString().let { println(it) } }
-->

/**
 * Returns a flow that mirrors the original flow, but filters out values
 * that are followed by the newer values within the given [timeout][timeoutMillis].
 * The latest value is always emitted.
 *
 * Example:
 *
 * ```kotlin
 * flow {
 *     emit(1)
 *     delay(90)
 *     emit(2)
 *     delay(90)
 *     emit(3)
 *     delay(1010)
 *     emit(4)
 *     delay(1010)
 *     emit(5)
 * }.debounce(1000)
 * ```
 * <!--- KNIT example-delay-01.kt -->
 *
 * produces the following emissions
 *
 * ```text
 * 3, 4, 5
 * ```
 * <!--- TEST -->
 *
 * Note that the resulting flow does not emit anything as long as the original flow emits
 * items faster than every [timeoutMillis] milliseconds.
 */
@FlowPreview
public fun <T> Flow<T>.debounce(timeoutMillis: Long): Flow<T> {
    require(timeoutMillis >= 0L) { "Debounce timeout should not be negative" }
    if (timeoutMillis == 0L) return this
    return debounceInternal { timeoutMillis }
}

/**
 * Returns a flow that mirrors the original flow, but filters out values
 * that are followed by the newer values within the given [timeout][timeoutMillis].
 * The latest value is always emitted.
 *
 * A variation of [debounce] that allows specifying the timeout value dynamically.
 *
 * Example:
 *
 * ```kotlin
 * flow {
 *     emit(1)
 *     delay(90)
 *     emit(2)
 *     delay(90)
 *     emit(3)
 *     delay(1010)
 *     emit(4)
 *     delay(1010)
 *     emit(5)
 * }.debounce {
 *     if (it == 1) {
 *         0L
 *     } else {
 *         1000L
 *     }
 * }
 * ```
 * <!--- KNIT example-delay-02.kt -->
 *
 * produces the following emissions
 *
 * ```text
 * 1, 3, 4, 5
 * ```
 * <!--- TEST -->
 *
 * Note that the resulting flow does not emit anything as long as the original flow emits
 * items faster than every [timeoutMillis] milliseconds.
 *
 * @param timeoutMillis [T] is the emitted value and the return value is timeout in milliseconds.
 */
@FlowPreview
@OverloadResolutionByLambdaReturnType
public fun <T> Flow<T>.debounce(timeoutMillis: (T) -> Long): Flow<T> =
    debounceInternal(timeoutMillis)

/**
 * Returns a flow that mirrors the original flow, but filters out values
 * that are followed by the newer values within the given [timeout].
 * The latest value is always emitted.
 *
 * Example:
 *
 * ```kotlin
 * flow {
 *     emit(1)
 *     delay(90.milliseconds)
 *     emit(2)
 *     delay(90.milliseconds)
 *     emit(3)
 *     delay(1010.milliseconds)
 *     emit(4)
 *     delay(1010.milliseconds)
 *     emit(5)
 * }.debounce(1000.milliseconds)
 * ```
 * <!--- KNIT example-delay-duration-01.kt -->
 *
 * produces the following emissions
 *
 * ```text
 * 3, 4, 5
 * ```
 * <!--- TEST -->
 *
 * Note that the resulting flow does not emit anything as long as the original flow emits
 * items faster than every [timeout] milliseconds.
 */
@FlowPreview
public fun <T> Flow<T>.debounce(timeout: Duration): Flow<T> =
    debounce(timeout.toDelayMillis())

/**
 * Returns a flow that mirrors the original flow, but filters out values
 * that are followed by the newer values within the given [timeout].
 * The latest value is always emitted.
 *
 * A variation of [debounce] that allows specifying the timeout value dynamically.
 *
 * Example:
 *
 * ```kotlin
 * flow {
 *     emit(1)
 *     delay(90.milliseconds)
 *     emit(2)
 *     delay(90.milliseconds)
 *     emit(3)
 *     delay(1010.milliseconds)
 *     emit(4)
 *     delay(1010.milliseconds)
 *     emit(5)
 * }.debounce {
 *     if (it == 1) {
 *         0.milliseconds
 *     } else {
 *         1000.milliseconds
 *     }
 * }
 * ```
 * <!--- KNIT example-delay-duration-02.kt -->
 *
 * produces the following emissions
 *
 * ```text
 * 1, 3, 4, 5
 * ```
 * <!--- TEST -->
 *
 * Note that the resulting flow does not emit anything as long as the original flow emits
 * items faster than every [timeout] unit.
 *
 * @param timeout [T] is the emitted value and the return value is timeout in [Duration].
 */
@FlowPreview
@JvmName("debounceDuration")
@OverloadResolutionByLambdaReturnType
public fun <T> Flow<T>.debounce(timeout: (T) -> Duration): Flow<T> =
    debounceInternal { emittedItem ->
        timeout(emittedItem).toDelayMillis()
    }

private fun <T> Flow<T>.debounceInternal(timeoutMillisSelector: (T) -> Long): Flow<T> =
    scopedFlow { downstream ->
        // Produce the values using the default (rendezvous) channel
        val values = produce {
            collect { value -> send(value ?: NULL) }
        }
        // Now consume the values
        var lastValue: Any? = null
        while (lastValue !== DONE) {
            var timeoutMillis = 0L // will be always computed when lastValue != null
            // Compute timeout for this value
            if (lastValue != null) {
                timeoutMillis = timeoutMillisSelector(NULL.unbox(lastValue))
                require(timeoutMillis >= 0L) { "Debounce timeout should not be negative" }
                if (timeoutMillis == 0L) {
                    downstream.emit(NULL.unbox(lastValue))
                    lastValue = null // Consume the value
                }
            }
            // assert invariant: lastValue != null implies timeoutMillis > 0
            assert { lastValue == null || timeoutMillis > 0 }
            // wait for the next value with timeout
            select<Unit> {
                // Set timeout when lastValue exists and is not consumed yet
                if (lastValue != null) {
                    onTimeout(timeoutMillis) {
                        downstream.emit(NULL.unbox(lastValue))
                        lastValue = null // Consume the value
                    }
                }
                values.onReceiveCatching { value ->
                    value
                        .onSuccess { lastValue = it }
                        .onFailure {
                            it?.let { throw it }
                            // If closed normally, emit the latest value
                            if (lastValue != null) downstream.emit(NULL.unbox(lastValue))
                            lastValue = DONE
                        }
                }
            }
        }
    }

/**
 * Returns a flow that emits only the latest value emitted by the original flow during the given sampling [period][periodMillis].
 *
 * Example:
 *
 * ```kotlin
 * flow {
 *     repeat(10) {
 *         emit(it)
 *         delay(110)
 *     }
 * }.sample(200)
 * ```
 * <!--- KNIT example-delay-03.kt -->
 *
 * produces the following emissions
 *
 * ```text
 * 1, 3, 5, 7, 9
 * ```
 * <!--- TEST -->
 *
 * Note that the latest element is not emitted if it does not fit into the sampling window.
 */
@FlowPreview
public fun <T> Flow<T>.sample(periodMillis: Long): Flow<T> {
    require(periodMillis > 0) { "Sample period should be positive" }
    return scopedFlow { downstream ->
        val values = produce(capacity = Channel.CONFLATED) {
            collect { value -> send(value ?: NULL) }
        }
        var lastValue: Any? = null
        val ticker = fixedPeriodTicker(periodMillis)
        while (lastValue !== DONE) {
            select<Unit> {
                values.onReceiveCatching { result ->
                    result
                        .onSuccess { lastValue = it }
                        .onFailure {
                            it?.let { throw it }
                            ticker.cancel(ChildCancelledException())
                            lastValue = DONE
                        }
                }

                // todo: shall be start sampling only when an element arrives or sample aways as here?
                ticker.onReceive {
                    val value = lastValue ?: return@onReceive
                    lastValue = null // Consume the value
                    downstream.emit(NULL.unbox(value))
                }
            }
        }
    }
}

/*
 * TODO this design (and design of the corresponding operator) depends on #540
 */
internal fun CoroutineScope.fixedPeriodTicker(
    delayMillis: Long,
): ReceiveChannel<Unit> {
    return produce(capacity = 0) {
        delay(delayMillis)
        while (true) {
            channel.send(Unit)
            delay(delayMillis)
        }
    }
}

/**
 * Returns a flow that emits only the latest value emitted by the original flow during the given sampling [period].
 *
 * Example:
 *
 * ```kotlin
 * flow {
 *     repeat(10) {
 *         emit(it)
 *         delay(110)
 *     }
 * }.sample(200.milliseconds)
 * ```
 * <!--- KNIT example-delay-duration-03.kt -->
 *
 * produces the following emissions
 *
 * ```text
 * 1, 3, 5, 7, 9
 * ```
 * <!--- TEST -->
 *
 * Note that the latest element is not emitted if it does not fit into the sampling window.
 */
@FlowPreview
public fun <T> Flow<T>.sample(period: Duration): Flow<T> = sample(period.toDelayMillis())

/**
 * Returns a flow that will emit a [TimeoutCancellationException] if the upstream doesn't emit an item within the given time.
 *
 * Example:
 *
 * ```kotlin
 * flow {
 *     emit(1)
 *     delay(100)
 *     emit(2)
 *     delay(100)
 *     emit(3)
 *     delay(1000)
 *     emit(4)
 * }.timeout(100.milliseconds).catch { exception ->
 *     if (exception is TimeoutCancellationException) {
 *         // Catch the TimeoutCancellationException emitted above.
 *         // Emit desired item on timeout.
 *         emit(-1)
 *     } else {
 *         // Throw other exceptions.
 *         throw exception
 *     }
 * }.onEach {
 *     delay(300) // This will not cause a timeout
 * }
 * ```
 * <!--- KNIT example-timeout-duration-01.kt -->
 *
 * produces the following emissions
 *
 * ```text
 * 1, 2, 3, -1
 * ```
 * <!--- TEST -->
 *
 * Note that delaying on the downstream doesn't trigger the timeout.
 *
 * @param timeout Timeout duration. If non-positive, the flow is timed out immediately
 */
@FlowPreview
public fun <T> Flow<T>.timeout(
    timeout: Duration
): Flow<T> = timeoutInternal(timeout)

private fun <T> Flow<T>.timeoutInternal(
    timeout: Duration
): Flow<T> = scopedFlow { downStream ->
    if (timeout <= Duration.ZERO) throw TimeoutCancellationException("Timed out immediately")
    val values = buffer(Channel.RENDEZVOUS).produceIn(this)
    whileSelect {
        values.onReceiveCatching { value ->
            value.onSuccess {
                downStream.emit(it)
            }.onFailure {
                it?.let { throw it }
                // Closed normally, break the loop
                return@onReceiveCatching false
            }
            return@onReceiveCatching true
        }
        onTimeout(timeout) {
            throw TimeoutCancellationException("Timed out waiting for $timeout")
        }
    }
}"}

{"file_path":"/project/kotlinx-coroutines-core/common/test/flow/TimeoutWithCallbackFlowTest.kt","content":"package kotlinx.coroutines.flow

import kotlinx.coroutines.*
import kotlin.test.*
import kotlin.time.Duration.Companion.seconds

/**
 * Test to verify that callbackFlow closed exceptions are propagated correctly when chained with timeout.
 * This tests the fix for the issue where exceptions from callbackFlow.close() were not being sent downstream
 * when callbackFlow was chained directly with timeout.
 */
class TimeoutWithCallbackFlowTest {

    @Test
    fun testCallbackFlowCloseExceptionPropagatedWithTimeout() = runTest {
        val expectedException = IllegalStateException("Test Exception")

        val flow = callbackFlow<Int> {
            close(expectedException)
        }.timeout(5.seconds)

        val caughtException = try {
            flow.collect()
            null
        } catch (e: Exception) {
            e
        }

        assertNotNull(caughtException)
        assertIs<IllegalStateException>(caughtException)
        assertEquals("Test Exception", caughtException.message)
    }

    @Test
    fun testCallbackFlowNormalCloseWithTimeout() = runTest {
        val flow = callbackFlow<Int> {
            // Normal close without exception
            close()
        }.timeout(5.seconds)

        val collectedValues = mutableListOf<Int>()
        var completed = false

        try {
            flow.collect { value ->
                collectedValues.add(value)
            }
            completed = true
        } catch (e: Exception) {
            fail("Should not throw exception on normal close: $e")
        }

        assertTrue(completed, "Flow should complete normally")
        assertTrue(collectedValues.isEmpty(), "Should collect no values")
    }

    @Test
    fun testCallbackFlowWithValuesAndCloseException() = runTest {
        val expectedException = RuntimeException("Error after emission")

        val flow = callbackFlow<Int> {
            trySend(1)
            trySend(2)
            close(expectedException)
        }.timeout(5.seconds)

        val collectedValues = mutableListOf<Int>()
        val caughtException = try {
            flow.collect { value ->
                collectedValues.add(value)
            }
            null
        } catch (e: Exception) {
            e
        }

        assertEquals(listOf(1, 2), collectedValues, "Should collect values before exception")
        assertNotNull(caughtException)
        assertIs<RuntimeException>(caughtException)
        assertEquals("Error after emission", caughtException.message)
    }

    @Test
    fun testCallbackFlowCloseExceptionWorksAfterCatch() = runTest {
        val expectedException = IllegalStateException("Test Exception")

        val flow = callbackFlow<Int> {
            close(expectedException)
        }.catch { throw it }.timeout(5.seconds)

        val caughtException = try {
            flow.collect()
            null
        } catch (e: Exception) {
            e
        }

        assertNotNull(caughtException)
        assertIs<IllegalStateException>(caughtException)
        assertEquals("Test Exception", caughtException.message)
    }

    @Test
    fun testCallbackFlowCloseExceptionWithOnEach() = runTest {
        val expectedException = IllegalStateException("Test Exception with onEach")

        val flow = callbackFlow<Int> {
            close(expectedException)
        }.onEach {}).timeout(5.seconds)

        val caughtException = try {
            flow.collect()
            null
        } catch (e: Exception) {
            e
        }

        assertNotNull(caughtException)
        assertIs<IllegalStateException>(caughtException)
        assertEquals("Test Exception with onEach", caughtException.message)
    }

    @Test
    fun testCallbackFlowCloseExceptionWithMap() = runTest {
        val expectedException = IllegalStateException("Test Exception with map")

        val flow = callbackFlow<Int> {
            close(expectedException)
        }.map { it }.timeout(5.seconds)

        val caughtException = try {
            flow.collect()
            null
        } catch (e: Exception) {
            e
        }

        assertNotNull(caughtException)
        assertIs<IllegalStateException>(caughtException)
        assertEquals("Test Exception with map", caughtException.message)
    }

    @Test
    fun testCallbackFlowCloseExceptionWithFilter() = runTest {
        val expectedException = IllegalStateException("Test Exception with filter")

        val flow = callbackFlow<Int> {
            close(expectedException)
        }.filter { true }.timeout(5.seconds)

        val caughtException = try {
            flow.collect()
            null
        } catch (e: Exception) {
            e
        }

        assertNotNull(caughtException)
        assertIs<IllegalStateException>(caughtException)
        assertEquals("Test Exception with filter", caughtException.message)
    }

    @Test
    fun testCallbackFlowCloseExceptionCancelledUpstream() = runTest {
        val flow = callbackFlow<Int> {
            trySend(1)
            trySend(2)
            delay(100)
            // This shouldn't be reached if the collector cancels
            trySend(3)
        }.timeout(50.milliseconds)

        val collectedValues = mutableListOf<Int>()
        val caughtException = try {
            flow.collect {
                collectedValues.add(it)
                delay(200) // Delay to trigger timeout
            }
            null
        } catch (e: Exception) {
            e
        }

        // In this case, we expect TimeoutCancellationException, not the callbackFlow exception
        assertNotNull(caughtException)
        assertIs<TimeoutCancellationException>(caughtException)
        // Values before timeout should still be collected
        // The exact behavior depends on timing, but at least one value should be collected
    }

    @Test
    fun testTimeoutBeforeCallbackFlowCloseWithException() = runTest {
        // This tests that if timeout occurs before callbackFlow closes with exception,
        // the timeout exception is thrown, not the close exception
        val flow = callbackFlow<Int> {
            trySend(1)
            delay(100)
            close(IllegalStateException("This should not be thrown"))
        }.timeout(50.milliseconds)

        val collectedValues = mutableListOf<Int>()
        val caughtException = try {
            flow.collect {
                collectedValues.add(it)
                delay(200) // Delay to trigger timeout
            }
            null
        } catch (e: Exception) {
            e
        }

        assertNotNull(caughtException)
        assertIs<TimeoutCancellationException>(caughtException)
    }
}"}

