    fun createDummyDispatcher(): CoroutineDispatcher = object : CoroutineDispatcher() {
        override val name: String get() = "DummyDispatcher"

        override fun isDispatchNeeded(context: CoroutineContext): Boolean {
            throw IllegalStateException("Dispatcher not available - simulating missing Main.immediate")
        }

        override fun dispatch(context: CoroutineContext, block: Runnable) {
