57→        var consumed = 0
58→        try {
59→            collect { value ->
60→                // Note: this for take is not written via collectWhile on purpose.
61→                // It checks condition first and then makes a tail-call to either emit or emitAbort.
62→                // This way normal execution does not require a state machine, only a termination (emitAbort).
63→                // See "TakeBenchmark" for comparision of different approaches.
64→                if (++consumed < count) {
65→                    return@collect emit(value)
66→                } else {
67→                    return@collect emitAbort(value)
68→                }
69→            }
70→        } catch (e: TakeFlowException) {
71→            // This came from emitAbort, swallow it since take successfully completed
72→            // No need to rethrow anything
73→        } catch (e: AbortFlowException) {
74→            // This AbortFlowException came from downstream (e.g., from first())
75→            // Re-throw it so upstream operators like onCompletion can handle it
76→            throw e
77→        }
78→    }
79→}
