{"file_path":"/project/IssueReproductionTest.kt","content":"package kotlinx.coroutines.future

import kotlinx.coroutines.*
import java.util.concurrent.CancellationException
import kotlin.test.*

/**
 * Reproduces the issue described in the bug report:
 * CoroutineScope.future() may trigger global exception handler on cancellation
 *
 * Expected behavior: `future` coroutine builder delivers all errors via the returned object, just like `async`
 * Actual behavior: `future` coroutine builder can suddenly trigger global exception handler that may crash the application
 */
class IssueReproductionTest {

    @Test
    fun testFutureCancellationDoesNotTriggerGlobalExceptionHandler() {
        val unhandledExceptions = mutableListOf<Throwable>()

        // Set up custom exception handler to capture any unhandled exceptions
        val oldHandler = Thread.getDefaultUncaughtExceptionHandler()
        try {
            val scope = CoroutineScope(Dispatchers.Default)

            var caughtException: Throwable? = null
            val exceptionCatcher = Thread.setDefaultUncaughtExceptionHandler { thread, throwable ->
                caughtException = throwable
                println("Global exception handler caught: $throwable")
            }

            // Reproduce the issue scenario
            val future = scope.future {
                // Simulate an exception
                error("foo")
            }

            // Cancel the future before the coroutine completes
            future.cancel(true)

            // Wait a bit to ensure any async processing completes
            Thread.sleep(200)

            // The test passes if no exception was thrown to the global handler
            assertNull(caughtException, "Global exception handler should not have been triggered")

            // Verify the future was cancelled
            assertTrue(future.isCancelled || future.isDone)

            Thread.setDefaultUncaughtExceptionHandler(exceptionCatcher)
        } finally {
            Thread.setDefaultUncaughtExceptionHandler(oldHandler)
        }
    }

    @Test
    fun testFutureWithNormalExceptionStillDeliversViaFuture() {
        val scope = CoroutineScope(Dispatchers.Default)

        val future = scope.future {
            error("expected error")
        }

        // Wait for completion
        Thread.sleep(100)

        // The exception should be delivered via the CompletableFuture
        assertTrue(future.isDone)
        assertTrue(future.isCompletedExceptionally)

        // Verify the exception is available via get (which throws ExecutionException)
        val executionException = assertFailsWith(ExecutionException::class) {
            future.get()
        }

        assertTrue(executionException.cause is IllegalStateException)
        assertEquals("expected error", executionException.cause?.message)
    }

    @Test
    fun testFutureCancellationWithExceptionInFinally() {
        val scope = CoroutineScope(Dispatchers.Default)

        var finallyExecuted = false
        val future = scope.future {
            try {
                // Never reaches here
                delay(Long.MAX_VALUE)
            } finally {
                finallyExecuted = true
                throw IllegalStateException("exception in finally")
            }
        }

        future.cancel(true)

        // Wait for cancellation to complete
        Thread.sleep(200)

        assertTrue(finallyExecuted, "Finally block should have executed")

        // The cancellation should not cause global exception handler to be called
        // The exception in finally should not crash the application
    }
}"}

