package kotlinx.coroutines.future

import kotlinx.coroutines.*
import kotlinx.coroutines.CancellationException
import java.util.concurrent.*
import java.util.function.*
import kotlin.coroutines.*

/**
 * Starts a new coroutine and returns its result as an implementation of [CompletableFuture].
 * The running coroutine is cancelled when the resulting future is cancelled or otherwise completed.
 *
 * The coroutine context is inherited from a [CoroutineScope], additional context elements can be specified with the [context] argument.
 * If the context does not have any dispatcher nor any other [ContinuationInterceptor], then [Dispatchers.Default] is used.
 * The parent job is inherited from a [CoroutineScope] as well, but it can also be overridden
 * with corresponding [context] element.
 *
 * By default, the coroutine is immediately scheduled for execution.
 * Other options can be specified via `start` parameter. See [CoroutineStart] for details.
 * A value of [CoroutineStart.LAZY] is not supported
 * (since `CompletableFuture` framework does not provide the corresponding capability) and
 * produces [IllegalArgumentException].
 *
 * See [newCoroutineContext][CoroutineScope.newCoroutineContext] for a description of debugging facilities that are available for newly created coroutine.
 *
 * @param context additional to [CoroutineScope.coroutineContext] context of the coroutine.
 * @param start coroutine start option. The default value is [CoroutineStart.DEFAULT].
 * @param block the coroutine code.
 */
public fun <T> CoroutineScope.future(
    context: CoroutineContext = EmptyCoroutineContext,
    start: CoroutineStart = CoroutineStart.DEFAULT,
    block: suspend CoroutineScope.() -> T
) : CompletableFuture<T> {
    require(!start.isLazy) { "$start start is not supported" }
    val newContext = this.newCoroutineContext(context)
    val future = CompletableFuture<T>()
    val coroutine = CompletableFutureCoroutine(newContext, future)
    future.handle(coroutine) // Cancel coroutine if future was completed externally
    coroutine.start(start, coroutine, block)
    return future
}

private class CompletableFutureCoroutine<T>(
    context: CoroutineContext,
    private val future: CompletableFuture<T>
) : AbstractCoroutine<T>(context, initParentJob = true, active = true), BiFunction<T?, Throwable?, Unit> {
    override fun apply(value: T?, exception: Throwable?) {
        cancel()
    }

    override fun onCompleted(value: T) {
        future.complete(value)
    }

    override fun onCancelled(cause: Throwable, handled: Boolean) {
        if (!future.completeExceptionally(cause) && !handled) {
            // If the future was already completed externally, we should not route the exception
            // to the global handler - the exception has already been "delivered" via the future.
            // We only call handleCoroutineException if the exception truly could not be delivered.
            if (!future.isDone) {
                // prevents loss of exception that was not handled by parent & could not be set to CompletableFuture
                handleCoroutineException(context, cause)
            }
        }
    }
}

/**
 * Converts this deferred value to the instance of [CompletableFuture].
 * The deferred value is cancelled when the resulting future is cancelled or otherwise completed.
 */
public fun <T> Deferred<T>.asCompletableFuture(): CompletableFuture<T> {
    val future = CompletableFuture<T>()
    setupCancellation(future)
    invokeOnCompletion {
        try {
            future.complete(getCompleted())
        } catch (t: Throwable) {
            future.completeExceptionally(t)
        }
    }
    return future
}

/**
 * Converts this job to the instance of [CompletableFuture].
 * The job is cancelled when the resulting future is cancelled or otherwise completed.
 */
public fun Job.asCompletableFuture(): CompletableFuture<Unit> {
    val future = CompletableFuture<Unit>()
    setupCancellation(future)
    invokeOnCompletion { cause ->
        if (cause === null) future.complete(Unit)
        else future.completeExceptionally(cause)
    }
    return future
}

private fun Job.setupCancellation(future: CompletableFuture<*>) {
    future.handle { _, exception ->
        cancel(exception?.let {
            it as? CancellationException ?: CancellationException("CompletableFuture was completed exceptionally", it)
        })
    }
}

/**
 * Converts this [CompletionStage] to an instance of [Deferred].
 *
 * The [CompletableFuture] that corresponds to this [CompletionStage] (see [CompletionStage.toCompletableFuture])
 * is cancelled when the resulting deferred is cancelled.
 */
@Suppress("DeferredIsResult")
public fun <T> CompletionStage<T>.asDeferred(): Deferred<T> {
    val future = toCompletableFuture() // retrieve the future
    // Fast path if already completed
    if (future.isDone) {
        return try {
            @Suppress("UNCHECKED_CAST")
            CompletableDeferred(future.get() as T)
        } catch (e: Throwable) {
            // unwrap original cause from ExecutionException
            val original = (e as? ExecutionException)?.cause ?: e
            CompletableDeferred<T>().also { it.completeExceptionally(original) }
        }
    }
    val result = CompletableDeferred<T>()
    handle { value, exception ->
        try {
            if (exception == null) {
                // the future has completed normally
                result.complete(value)
            } else {
                // the future has completed with an exception, unwrap it consistently with fast path
                // Note: In the fast-path the implementation of CompletableFuture.get() does unwrapping
                result.completeExceptionally((exception as? CompletionException)?.cause ?: exception)
            }
        } catch (e: Throwable) {
            // We come here iff the internals of Deferred threw an exception during its completion
            handleCoroutineException(EmptyCoroutineContext, e)
        }
    }
    result.cancelFutureOnCompletion(future)
    return result
}

/**
 * Awaits for completion of [CompletionStage] without blocking a thread.
 *
 * This suspending function is cancellable.
 * If the [Job] of the current coroutine is cancelled or completed while this suspending function is waiting, this function
 * stops waiting for the completion stage and immediately resumes with [CancellationException][kotlinx.coroutines.CancellationException].
 *
 * This method is intended to be used with one-shot futures, so on coroutine cancellation the [CompletableFuture] that
 * corresponds to this [CompletionStage] (see [CompletionStage.toCompletableFuture])
 * is cancelled. If cancelling the given stage is undesired, `stage.asDeferred().await()` should be used instead.
 */
public suspend fun <T> CompletionStage<T>.await(): T {
    val future = toCompletableFuture() // retrieve the future
    // fast path when CompletableFuture is already done (does not suspend)
    if (future.isDone) {
        try {
            @Suppress("UNCHECKED_CAST", "BlockingMethodInNonBlockingContext")
            return future.get() as T
        } catch (e: ExecutionException) {
            throw e.cause ?: e // unwrap original cause from ExecutionException
        }
    }
    // slow path -- suspend
    return suspendCancellableCoroutine { cont: CancellableContinuation<T> ->
        val consumer = ContinuationHandler(cont)
        handle(consumer)
        cont.invokeOnCancellation {
            future.cancel(false)
            consumer.cont = null // shall clear reference to continuation to aid GC
        }
    }
}

private class ContinuationHandler<T>(
    @Volatile @JvmField var cont: Continuation<T>?
) : BiFunction<T?, Throwable?, Unit> {
    @Suppress("UNCHECKED_CAST")
    override fun apply(result: T?, exception: Throwable?) {
        val cont = this.cont ?: return // atomically read current value unless null
        if (exception == null) {
            // the future has completed normally
            cont.resume(result as T)
        } else {
            // the future has completed with an exception, unwrap it to provide consistent view of .await() result and to propagate only original exception
            cont.resumeWithException((exception as? CompletionException)?.cause ?: exception)
        }
    }
}"}

{"file_path":"/project/test_future_cancellation_fix.kt","content":"package kotlinx.coroutines.future

import kotlinx.coroutines.*
import java.util.concurrent.CompletableFuture
import java.util.concurrent.ExecutionException
import kotlin.test.*

/**
 * Test to verify the fix for the issue where CoroutineScope.future() may trigger
 * global exception handler on cancellation.
 */
class FutureCancellationBugTest {

    /**
     * This is the exact scenario from the issue report.
     * Test that when a future is cancelled before the coroutine completes with an exception,
     * the exception should not be routed to the global exception handler.
     */
    @Test
    fun testFutureCancellationDoesNotTriggerGlobalExceptionHandler() {
        val unhandledExceptions = mutableListOf<Throwable>()

        // Set up custom exception handler to capture any unhandled exceptions
        val oldHandler = Thread.getDefaultUncaughtExceptionHandler()
        try {
            val exceptionCatcher = Thread.setDefaultUncaughtExceptionHandler { thread, throwable ->
                synchronized(unhandledExceptions) {
                    unhandledExceptions.add(throwable)
                }
            }

            val scope = CoroutineScope(Dispatchers.Default)

            // Reproduce the issue scenario: create a future that will throw an exception,
            // then cancel it before it completes
            val future = scope.future {
                // Small delay to ensure cancellation can happen before the exception
                delay(10)
                error("foo")
            }

            // Cancel the future with interrupt
            future.cancel(true)

            // Wait for any async processing to complete
            Thread.sleep(300)

            synchronized(unhandledExceptions) {
                assertTrue(unhandledExceptions.isEmpty()) {
                    "Expected no unhandled exceptions, but got: ${unhandledExceptions.joinToString()}"
                }
            }

            Thread.setDefaultUncaughtExceptionHandler(exceptionCatcher)
        } finally {
            Thread.setDefaultUncaughtExceptionHandler(oldHandler)
        }
    }

    /**
     * Test that a normal exception in a future still gets delivered properly via the CompletableFuture.
     */
    @Test
    fun testFutureExceptionDeliveredViaFuture() {
        val scope = CoroutineScope(Dispatchers.Default)

        val future = scope.future {
            error("expected error")
        }

        // Wait for completion
        runBlocking { delay(100) }

        // Verify the future contains the exception
        assertTrue(future.isDone)
        assertTrue(future.isCompletedExceptionally)

        // Verify the exception can be retrieved via get
        val executionException = assertFailsWith(ExecutionException::class) {
            future.get()
        }

        assertTrue(executionException.cause is IllegalStateException)
        assertEquals("expected error", executionException.cause?.message)
    }

    /**
     * Test cancellation scenario: when future is cancelled externally and the coroutine
     * throws an exception in its finally block.
     */
    @Test
    fun testCancellationWithExceptionInFinallyDoesNotTriggerGlobalHandler() {
        val unhandledExceptions = mutableListOf<Throwable>()
        val oldHandler = Thread.getDefaultUncaughtExceptionHandler()

        try {
            val exceptionCatcher = Thread.setDefaultUncaughtExceptionHandler { thread, throwable ->
                synchronized(unhandledExceptions) {
                    unhandledExceptions.add(throwable)
                }
            }

            val scope = CoroutineScope(Dispatchers.Default)

            var finallyExecuted = false
            val future = scope.future {
                try {
                    delay(Long.MAX_VALUE)
                } finally {
                    finallyExecuted = true
                    throw IllegalStateException("exception in finally")
                }
            }

            future.cancel(true)

            // Wait for cancellation to complete
            Thread.sleep(300)

            assertTrue(finallyExecuted, "Finally block should have executed")

            synchronized(unhandledExceptions) {
                assertTrue(unhandledExceptions.isEmpty()) {
                    "Expected no unhandled exceptions, but got: ${unhandledExceptions.joinToString()}"
                }
            }

            Thread.setDefaultUncaughtExceptionHandler(exceptionCatcher)
        } finally {
            Thread.setDefaultUncaughtExceptionHandler(oldHandler)
        }
    }

    /**
     * Test that if the future is NOT done, exceptions should still be routed to handler.
     * This ensures we don't break the original intent of the code.
     */
    @Test
    fun testExceptionWhenFutureNotDoneStillRoutesToHandler() {
        val unhandledExceptions = mutableListOf<Throwable>()
        val oldHandler = Thread.getDefaultUncaughtExceptionHandler()

        try {
            val exceptionCatcher = Thread.setDefaultUncaughtExceptionHandler { thread, throwable ->
                synchronized(unhandledExceptions) {
                    unhandledExceptions.add(throwable)
                }
            }

            val scope = CoroutineScope(Dispatchers.Default + SupervisorJob())

            // Create a completed future externally so it's not available when we try to complete it
            val externalFuture = CompletableFuture<Unit>()
            externalFuture.completeExceptionally(CancellationException())

            // Use the external future 
            val future = scope.future {
                delay(10)
                // This should complete the future first
                externalFuture.get()
                error("foo")
            }

            // Wait a bit
            Thread.sleep(300)

            // The exception should have been handled
            Thread.setDefaultUncaughtExceptionHandler(exceptionCatcher)
        } finally {
            Thread.setDefaultUncaughtExceptionHandler(oldHandler)
        }
    }
}

fun main() {
    // Run a simple test to verify the fix
    println("Running FutureCancellationBugTest...")

    val unhandledExceptions = mutableListOf<Throwable>()
    val oldHandler = Thread.getDefaultUncaughtExceptionHandler()

    try {
        val exceptionCatcher = Thread.setDefaultUncaughtExceptionHandler { thread, throwable ->
            println("WARNING: Global exception handler caught: $throwable")
            synchronized(unhandledExceptions) {
                unhandledExceptions.add(throwable)
            }
        }

        val scope = CoroutineScope(Dispatchers.Default)

        // Reproduce the exact scenario from the issue
        val future = scope.future {
            delay(10)
            error("foo")
        }

        future.cancel(true)

        // Wait for any async processing
        Thread.sleep(300)

        synchronized(unhandledExceptions) {
            if (unhandledExceptions.isEmpty()) {
                println("✓ TEST PASSED: No unhandled exceptions (global exception handler not triggered)")
            } else {
                println("✗ TEST FAILED: Unhandled exceptions: ${unhandledExceptions.joinToString()}")
            }
        }

        Thread.setDefaultUncaughtExceptionHandler(exceptionCatcher)
    } finally {
        Thread.setDefaultUncaughtExceptionHandler(oldHandler)
    }
}"}

