{"file_path":"project/ComprehensiveFutureCancellationTest.kt","content":"package kotlinx.coroutines.future

import kotlinx.coroutines.*
import java.util.concurrent.CompletableFuture
import kotlin.test.*

/**
 * Comprehensive tests to verify the fix for the issue where
 * CoroutineScope.future() may trigger global exception handler on cancellation.
 */
class ComprehensiveFutureCancellationTest {

    /**
     * TEST 1: The exact scenario from the issue report
     * When a future is cancelled before the coroutine completes with an exception,
     * the exception should NOT trigger the global exception handler.
     */
    @Test
    fun testIssueScenario_CancelledFutureDoesNotTriggerGlobalHandler() {
        val unhandledExceptions = mutableListOf<Throwable>()
        val oldHandler = Thread.getDefaultUncaughtExceptionHandler()

        try {
            val exceptionCatcher = Thread.setDefaultUncaughtExceptionHandler { thread, throwable ->
                synchronized(unhandledExceptions) {
                    unhandledExceptions.add(throwable)
                }
            }

            // Exact scenario from the issue
            val scope = CoroutineScope(Dispatchers.Default)
            val future = scope.future {
                delay(10)  // Give cancellation time to happen
                error("foo")
            }
            future.cancel(true)
            Thread.sleep(300)

            assertTrue(unhandledExceptions.isEmpty(), 
                "Expected no unhandled exceptions, but got: ${unhandledExceptions.joinToString()}")

            Thread.setDefaultUncaughtExceptionHandler(exceptionCatcher)
        } finally {
            Thread.setDefaultUncaughtExceptionHandler(oldHandler)
        }
    }

    /**
     * TEST 2: Cancellation with exception in finally block
     * Even when the finally block throws an exception, it should not trigger the global handler.
     */
    @Test
    fun testCancellationWithExceptionInFinally() {
        val unhandledExceptions = mutableListOf<Throwable>()
        val oldHandler = Thread.getDefaultUncaughtExceptionHandler()

        try {
            val exceptionCatcher = Thread.setDefaultUncaughtExceptionHandler { thread, throwable ->
                synchronized(unhandledExceptions) {
                    unhandledExceptions.add(throwable)
                }
            }

            val scope = CoroutineScope(Dispatchers.Default)
            var finallyExecuted = false

            val future = scope.future {
                try {
                    delay(Long.MAX_VALUE)
                } finally {
                    finallyExecuted = true
                    throw IllegalStateException("exception in finally after cancellation")
                }
            }
            future.cancel(true)
            Thread.sleep(300)

            assertTrue(finallyExecuted)
            assertTrue(unhandledExceptions.isEmpty(),
                "Expected no unhandled exceptions, but got: ${unhandledExceptions.joinToString()}")
            assertTrue(future.isCancelled)

            Thread.setDefaultUncaughtExceptionHandler(exceptionCatcher)
        } finally {
            Thread.setDefaultUncaughtExceptionHandler(oldHandler)
        }
    }

    /**
     * TEST 3: Normal exception in a future should still be delivered via the future
     */
    @Test
    fun testNormalExceptionDeliveredViaFuture() {
        val scope = CoroutineScope(Dispatchers.Default)
        val future = scope.future {
            error("expected error")
        }

        runBlocking { delay(100) }

        assertTrue(future.isDone)
        assertTrue(future.isCompletedExceptionally)

        val executionException = assertFailsWith(java.util.concurrent.ExecutionException::class) {
            future.get()
        }

        assertTrue(executionException.cause is IllegalStateException)
        assertEquals("expected error", executionException.cause?.message)
    }

    /**
     * TEST 4: External completion (NOT cancelled) with exception should still trigger global handler
     * This ensures we don't break the expected behavior from testUnhandledExceptionOnExternalCompletion
     */
    @Test
    fun testExternalCompletionRoutesExceptionsToHandler() {
        val unhandledExceptions = mutableListOf<Throwable>()
        val oldHandler = Thread.getDefaultUncaughtExceptionHandler()

        try {
            val exceptionCatcher = Thread.setDefaultUncaughtExceptionHandler { thread, throwable ->
                println("Global handler caught: $throwable")
                synchronized(unhandledExceptions) {
                    unhandledExceptions.add(throwable)
                }
            }

            val scope = CoroutineScope(Dispatchers.Default + NonCancellable)
            var finallyExecuted = false

            val future = scope.future {
                try {
                    delay(1000)
                } finally {
                    finallyExecuted = true
                    throw TestException("exception in finally")
                }
            }

            // Complete externally (NOT cancel)
            @Suppress("DEPRECATION")
            future.complete(Unit)
            Thread.sleep(300)

            assertTrue(finallyExecuted)
            assertFalse(unhandledExceptions.isEmpty(),
                "Expected exception to be routed to handler after external completion")

            Thread.setDefaultUncaughtExceptionHandler(exceptionCatcher)
        } finally {
            Thread.setDefaultUncaughtExceptionHandler(oldHandler)
        }
    }

    /**
     * TEST 5: Verify future properties after cancellation
     */
    @Test
    fun testCancelledFutureProperties() {
        val scope = CoroutineScope(Dispatchers.Default)
        val future = scope.future {
            delay(Long.MAX_VALUE)
        }

        assertFalse(future.isDone)
        assertFalse(future.isCancelled)

        future.cancel(true)
        Thread.sleep(100)

        assertTrue(future.isDone)
        assertTrue(future.isCancelled)
        assertTrue(future.isCompletedExceptionally)

        // Verify future.get() throws CancellationException
        try {
            future.get()
            fail("future.get() should throw exception")
        } catch (e: java.util.concurrent.ExecutionException) {
            assertTrue(e.cause is java.util.concurrent.CancellationException)
        }
    }

    /**
     * TEST 6: Multiple rapid cancellations should be safe
     */
    @Test
    fun testMultipleRapidCancellations() {
        val unhandledExceptions = mutableListOf<Throwable>()
        val oldHandler = Thread.getDefaultUncaughtExceptionHandler()

        try {
            val exceptionCatcher = Thread.setDefaultUncaughtExceptionHandler { thread, throwable ->
                synchronized(unhandledExceptions) {
                    unhandledExceptions.add(throwable)
                }
            }

            val scope = CoroutineScope(Dispatchers.Default)
            val future = scope.future {
                try {
                    delay(100)
                } finally {
                    throw IllegalStateException("finally exception")
                }
            }

            // Cancel multiple times
            repeat(5) { future.cancel(true) }
            Thread.sleep(300)

            assertTrue(unhandledExceptions.isEmpty())
            assertTrue(future.isCancelled)

            Thread.setDefaultUncaughtExceptionHandler(exceptionCatcher)
        } finally {
            Thread.setDefaultUncaughtExceptionHandler(oldHandler)
        }
    }
}"}

